#include <bits/stdc++.h>
using namespace std;
int main() {
    int N;
    cin >> N;
    string S;
    cin >> S;
    int M;
    cin >> M;
    string T;
    cin >> T;
    int m = S.size(), n = T.size();
    vector<vector<int>> dp(m + 1, vector<int>(n + 1, INT_MAX));
    dp[0][0] = 0;
    for (int i = 0; i <= m; i++) {
        for (int j = 0; j <= n; j++) {
            if (i < m) {
                dp[i + 1][j] = min(dp[i + 1][j], dp[i][j]);
            }
            if (j < n && i < m) {
                if (S[i] == T[j]) {
                    dp[i + 1][j + 1] = min(dp[i + 1][j + 1], dp[i][j] + 1);
                } else {
                    dp[i + 1][j + 1] = min(dp[i + 1][j + 1], dp[i][j + 1]);
                }
            }
        }
    }
    int res = dp[m][n];
    cout << (res == INT_MAX ? -1 : res) << endl;
}
